#!/usr/bin/env python3
from pathlib import Path
import base64

ROOT = Path.cwd()

required = ["package.json", "app", "lib", "public"]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

icons = {'public/icon-192.png': '', 'public/icon-512.png': '', 'public/apple-touch-icon.png': '', 'public/favicon-32.png': ''}
for rel, data in icons.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(base64.b64decode(data))

# Añade helpers de countdown si no existen.
format_path = ROOT / "lib/format.ts"
format_content = format_path.read_text(encoding="utf-8")
if "formatStartsIn" not in format_content:
    format_path.write_text(format_content.rstrip() + "\n\n" + 'export function getMatchStartDate(matchDate?: string, timeEt?: string): Date | undefined {\n  if (!matchDate || !timeEt) return undefined;\n\n  const [rawHour, rawMinute = "00"] = timeEt.split(":");\n  const hour = Number(rawHour);\n  const minute = Number(rawMinute);\n\n  if (!Number.isFinite(hour) || !Number.isFinite(minute)) return undefined;\n\n  // En junio/julio, Eastern Time = UTC-4, así que UTC = ET + 4 horas.\n  return new Date(`${matchDate}T${String(hour + 4).padStart(2, "0")}:${String(minute).padStart(2, "0")}:00Z`);\n}\n\nexport function formatStartsIn(matchDate?: string, timeEt?: string): string {\n  const start = getMatchStartDate(matchDate, timeEt);\n  if (!start) return "Hora pendiente";\n\n  const diffMs = start.getTime() - Date.now();\n\n  if (diffMs <= -2 * 60 * 60 * 1000) return "Ya jugado";\n  if (diffMs <= 0) return "En juego";\n\n  const totalMinutes = Math.round(diffMs / 60000);\n  const days = Math.floor(totalMinutes / (60 * 24));\n  const hours = Math.floor((totalMinutes - days * 24 * 60) / 60);\n  const minutes = totalMinutes % 60;\n\n  if (days > 0) return `Empieza en ${days}d ${hours}h`;\n  if (hours > 0) return `Empieza en ${hours}h ${minutes}m`;\n  return `Empieza en ${minutes}m`;\n}\n' + "\n", encoding="utf-8")

# Cambia la home.
(ROOT / "app/page.tsx").write_text('import { MatchCard } from "@/components/MatchCard";\nimport { StandingCard } from "@/components/StandingCard";\nimport { formatStartsIn } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches, getNextMatch, getStandings } from "@/lib/scoring";\n\nexport const revalidate = 60;\n\nexport default async function HomePage() {\n  const payload = await getFootballDataResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const total = getMatches().length;\n  const nextMatch = getNextMatch(payload.results);\n  const podium = standings.slice(0, 3);\n  const rest = standings.slice(3);\n\n  return (\n    <section className="screen">\n      <header className="app-header hero-sport">\n        <div>\n          <div className="section-label">Ranking en directo</div>\n          <h1>🏆 Mundial 2026</h1>\n          {nextMatch ? (\n            <div className="hero-next">\n              <div>{nextMatch.home} - {nextMatch.away}</div>\n              <span>{formatStartsIn(nextMatch.date, nextMatch.timeEt)}</span>\n            </div>\n          ) : (\n            <p>{played}/{total} partidos puntuados</p>\n          )}\n        </div>\n        <div className="live-badge">Live</div>\n      </header>\n\n      {payload.error ? (\n        <div className="system-notice">La API no ha respondido correctamente. Reintentará en la próxima carga.</div>\n      ) : null}\n\n      {nextMatch ? (\n        <section className="block">\n          <div className="block-heading">\n            <h2>Próximo partido</h2>\n            <span>{played}/{total} puntuados</span>\n          </div>\n          <MatchCard match={nextMatch} result={payload.results[nextMatch.id]} featured />\n        </section>\n      ) : null}\n\n      {played === 0 ? (\n        <section className="quiet-card">\n          <h2>Todo preparado</h2>\n          <p>La clasificación empezará a moverse en cuanto finalice el primer partido.</p>\n        </section>\n      ) : null}\n\n      <section className="block">\n        <div className="block-heading">\n          <h2>Ranking</h2>\n          <span>1 punto por acierto</span>\n        </div>\n\n        <div className="podium">\n          {podium.map((row, index) => (\n            <a key={row.player} href={`/pronosticos/${encodeURIComponent(row.player)}`} className={`podium-card rank-${index + 1}`}>\n              <div className="podium-top">#{index + 1}</div>\n              <div className="podium-name">{row.player}</div>\n              <div className="podium-score">{row.points}</div>\n              <div className="muted">{row.played === 0 ? "Salida" : `${row.correct}/${row.played} · ${row.percentage}%`}</div>\n            </a>\n          ))}\n        </div>\n\n        <div className="standing-list">\n          {rest.map((row, index) => (\n            <StandingCard key={row.player} row={row} position={index + 4} compact />\n          ))}\n        </div>\n      </section>\n    </section>\n  );\n}\n', encoding="utf-8")

# Añade CSS de cabecera.
css_path = ROOT / "app/globals.css"
css = css_path.read_text(encoding="utf-8")
marker = "/* V7: icono opción B y cabecera deportiva */"
if marker not in css:
    css_path.write_text(css.rstrip() + "\n\n" + '/* V7: icono opción B y cabecera deportiva */\n.hero-sport h1 {\n  font-size: 36px;\n  letter-spacing: -0.035em;\n}\n\n.hero-next {\n  margin-top: 14px;\n  padding: 14px;\n  border: 1px solid rgba(44, 37, 25, 0.08);\n  border-radius: 22px;\n  background: #fff;\n  box-shadow: 0 10px 24px rgba(77, 54, 13, 0.06);\n}\n\n.hero-next div {\n  color: var(--ink);\n  font-size: 20px;\n  line-height: 1.05;\n  letter-spacing: -0.035em;\n  font-weight: 820;\n}\n\n.hero-next span {\n  display: inline-block;\n  margin-top: 6px;\n  color: #cf7a00;\n  font-size: 15px;\n  font-weight: 820;\n}\n\n@media (max-width: 390px) {\n  .hero-sport h1 {\n    font-size: 32px;\n  }\n\n  .hero-next div {\n    font-size: 18px;\n  }\n}\n' + "\n", encoding="utf-8")

print("V7 aplicada: icono opción B sin borde blanco añadido y cabecera tipo partido próximo con countdown.")
print("Ejecuta: npm run build && git add . && git commit -m 'Improve icon and home header' && git push && npx vercel --prod")
